# scripts/check_prompt_eval_coverage.py
# Run in CI on every PR to flag prompt/tool/guardrail changes with no linked eval case.

import subprocess, re, sys

TYPES_REQUIRING_EVAL = {"prompt", "guardrail", "tool", "agent"}

def get_pr_commits() -> list[tuple[str, str]]:
    """Return (sha, full_message) for each commit in this PR."""
    shas = subprocess.check_output(
        ["git", "log", "origin/main..HEAD", "--format=%H"], text=True
    ).splitlines()
    result = []
    for sha in shas:
        msg = subprocess.check_output(["git", "show", "-s", "--format=%B", sha], text=True)
        result.append((sha, msg))
    return result

def get_commit_type(subject: str) -> str | None:
    m = re.match(r'^(\w+)(\([^)]+\))?:', subject)
    return m.group(1) if m else None

def has_eval_case_trailer(message: str) -> bool:
    return bool(re.search(r'^Eval-case:', message, re.MULTILINE))

violations = []
for sha, message in get_pr_commits():
    subject = message.splitlines()[0] if message.strip() else ""
    commit_type = get_commit_type(subject)
    if commit_type in TYPES_REQUIRING_EVAL and not has_eval_case_trailer(message):
        violations.append((sha[:8], subject))

if violations:
    print(f"COVERAGE GAP: {len(violation)} commit(s) lack Eval-case trailers:")
    for sha, subject in violations:
        print(f"  {sha}: {subject}")
    print("\nAdd 'Eval-case: <id>[, <id>]' to each commit message or amend the commit.")
    sys.exit(1)

print("Eval coverage check passed.")

# src/observability/deployment_trace.py
"""Emit deployment metadata to your observability platform on startup."""
import subprocess, json, datetime, os
import logging

log = logging.getLogger(__name__)

def get_deployment_metadata() -> dict:
    """Collect commit SHA, eval case IDs from recent commits, and prompt version."""
    try:
        sha = subprocess.check_output(["git", "rev-parse", "HEAD"], text=True).strip()
        # Get Eval-case trailers from the last 10 commits on this branch
        log_output = subprocess.check_output(
            ["git", "log", "-10", "--format=%B%x00"], text=True
        )
        eval_cases: list[str] = []
        for message in log_output.split("\x00"):
            for line in message.splitlines():
                if line.startswith("Eval-case:"):
                    cases = [c.strip() for c in line.replace("Eval-case:", "").split(",")]
                    eval_cases.extend(cases)
        eval_cases = list(dict.fromkeys(eval_cases))   # deduplicate, preserve order

        return {
            "commit_sha": sha[:8],
            "eval_cases_covered": eval_cases,
            "deployed_at": datetime.datetime.utcnow().isoformat() + "Z",
            "environment": os.environ.get("DEPLOY_ENV", "unknown"),
        }
    except Exception as e:
        log.warning(f"Could not collect deployment metadata: {e}")
        return {}

def emit_deployment_event(metadata: dict) -> None:
    """Log structured deployment metadata on application startup."""
    log.info("Deployment metadata", extra={"deployment": metadata})
